          addr.getHostAddress == "::"
      }
    }.getOrElse(true) // If DNS resolution fails, block it
  }

  private def isDomainAllowed(host: String): Boolean = {
    val lowerHost = host.toLowerCase
    allowedDomainSuffixes.exists(suffix => lowerHost.endsWith(suffix) || lowerHost == suffix.stripPrefix("."))
